Rules.InvariantScript:
Patch(
    EmergencyIncidents,
    LookUp(EmergencyIncidents, ID = varSelectedIncident.ID),
    {
        Status: {Value: "On the Way"},
        'Last Updated': Now()
    }
);

Refresh(EmergencyIncidents);

Set(
    varSelectedIncident,
    LookUp(EmergencyIncidents, ID = varSelectedIncident.ID)
);

Navigate(DispatchTrackingScreen, ScreenTransition.Fade)

Patch(
    EmergencyIncidents,
    LookUp(EmergencyIncidents, ID = varSelectedIncident.ID),
    {
        Status: {Value: "False Report"},
        'Last Updated': Now()
    }
);

Refresh(EmergencyIncidents);

Set(varSelectedIncident, Blank());

Navigate(IncidentOverviewScreen, ScreenTransition.Fade)

Set(
    varSelectedIncident,
    Patch(
        EmergencyIncidents,
        varSelectedIncident,
        {
            Status: {Value: "On the Way"},
            'Support Requested': true,
            'Last Updated': Now()
        }
    )
);

Refresh(EmergencyIncidents);

Navigate(DispatchTrackingScreen, ScreenTransition.Fade)
